module top_module(input [2:0] obf_immediate,
              output reg[7:0] extended
    );always @(obf_immediate)begin
  if(obf_immediate[2]==1)
   begin 
    extended[7:3]=5'b11111;
    extended[2:0]=obf_immediate;
   end

   if(obf_immediate[2]==0)begin 
   extended[7:3]=5'b00000;
   extended[2:0]=obf_immediate;
   end
   end


endmodule
